CREATE TABLE users (id INTEGER, name TEXT);
CREATE TABLE orders (id INTEGER, user_id INTEGER, total REAL);

INSERT INTO users VALUES (1,'Alice'),(2,'Bob'),(3,'Carol'),(4,'Dave');
INSERT INTO orders VALUES (1,1,50),(2,1,120),(3,3,30);

-- Users who placed at least one order
SELECT name FROM users
WHERE id IN (
  SELECT DISTINCT user_id FROM orders
)
ORDER BY name;

CREATE TABLE products (name TEXT, price REAL);
INSERT INTO products VALUES ('Widget',9.99),('Gadget',49.99),('Thingamajig',24.99),('Gizmo',99.99),('Doohickey',14.99);

-- Products more expensive than average
SELECT name, price FROM products
WHERE price > (SELECT AVG(price) FROM products)
ORDER BY price DESC;

CREATE TABLE departments (id INTEGER, name TEXT);
CREATE TABLE employees (id INTEGER, dept_id INTEGER, name TEXT);

INSERT INTO departments VALUES (1,'Engineering'),(2,'Marketing'),(3,'Legal');
INSERT INTO employees VALUES (1,1,'Alice'),(2,1,'Bob'),(3,2,'Carol');

-- Departments that have at least one employee
SELECT name FROM departments d
WHERE EXISTS (
  SELECT 1 FROM employees WHERE dept_id = d.id
)
ORDER BY name;
